protected SalesQuotationCopyingContract createContract()
{
    SalesQuotationCopyingContract contract = next createContract();

    contract.parmCopyHeaderTextBlock(CopyTextblock_Header.value());
    contract.parmCopyLineTextBlock(CopyTextblock_Line.value());

    return contract;
}

void  init()
{

    next init();

    if (callerSalesQuotationTable.QuotationType == QuotationType::Project)
    {
        ProjFormletterParameters param = ProjFormletterParameters::find();
        CopyTextblock_Header.value(param.FWFTextBlockQuotationCopyingHeader);
        CopyTextblock_Line.value(param.FWFTextBlockQuotationCopyingLine);
    }
    else //QuotationType::Sales
    {
        CustFormletterParameters param = CustFormletterParameters::find();
        CopyTextblock_Header.value(param.FWFTextBlockQuotationCopyingHeader);
        CopyTextblock_Line.value(param.FWFTextBlockQuotationCopyingLine);
    }
}
